CREATE OR ALTER TRIGGER [edfi].[TR_EducationOrganizationInterventionPrescriptionAssociation_ReferentialIdentity]
ON [edfi].[EducationOrganizationInterventionPrescriptionAssociation]
AFTER INSERT, UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM deleted)
    BEGIN
        DELETE FROM [dms].[ReferentialIdentity]
        WHERE [DocumentId] IN (SELECT [DocumentId] FROM inserted) AND [ResourceKeyId] = 99;
        INSERT INTO [dms].[ReferentialIdentity] ([ReferentialId], [DocumentId], [ResourceKeyId])
        SELECT [dms].[uuidv5]('edf1edf1-3df1-3df1-3df1-3df1edf1edf1', CAST(N'Ed-FiEducationOrganizationInterventionPrescriptionAssociation' AS nvarchar(max)) + N'$$.educationOrganizationReference.educationOrganizationId=' + CAST(i.[EducationOrganization_EducationOrganizationId] AS nvarchar(max)) + N'#' + N'$$.interventionPrescriptionReference.educationOrganizationId=' + CAST(i.[InterventionPrescriptionInterventionPrescription_EducationOrganizationId] AS nvarchar(max)) + N'#' + N'$$.interventionPrescriptionReference.interventionPrescriptionIdentificationCode=' + i.[InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode]), i.[DocumentId], 99
        FROM inserted i;
    END
    ELSE IF (UPDATE([EducationOrganization_EducationOrganizationId]) OR UPDATE([InterventionPrescriptionInterventionPrescription_EducationOrganizationId]) OR UPDATE([InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode]))
    BEGIN
        DECLARE @changedDocs TABLE ([DocumentId] bigint NOT NULL);
        INSERT INTO @changedDocs ([DocumentId])
        SELECT i.[DocumentId]
        FROM inserted i INNER JOIN deleted d ON d.[DocumentId] = i.[DocumentId]
        WHERE (i.[EducationOrganization_EducationOrganizationId] <> d.[EducationOrganization_EducationOrganizationId] OR (i.[EducationOrganization_EducationOrganizationId] IS NULL AND d.[EducationOrganization_EducationOrganizationId] IS NOT NULL) OR (i.[EducationOrganization_EducationOrganizationId] IS NOT NULL AND d.[EducationOrganization_EducationOrganizationId] IS NULL)) OR (i.[InterventionPrescriptionInterventionPrescription_EducationOrganizationId] <> d.[InterventionPrescriptionInterventionPrescription_EducationOrganizationId] OR (i.[InterventionPrescriptionInterventionPrescription_EducationOrganizationId] IS NULL AND d.[InterventionPrescriptionInterventionPrescription_EducationOrganizationId] IS NOT NULL) OR (i.[InterventionPrescriptionInterventionPrescription_EducationOrganizationId] IS NOT NULL AND d.[InterventionPrescriptionInterventionPrescription_EducationOrganizationId] IS NULL)) OR (i.[InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode] <> d.[InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode] OR (i.[InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode] IS NULL AND d.[InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode] IS NOT NULL) OR (i.[InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode] IS NOT NULL AND d.[InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode] IS NULL));
        DELETE FROM [dms].[ReferentialIdentity]
        WHERE [DocumentId] IN (SELECT [DocumentId] FROM @changedDocs) AND [ResourceKeyId] = 99;
        INSERT INTO [dms].[ReferentialIdentity] ([ReferentialId], [DocumentId], [ResourceKeyId])
        SELECT [dms].[uuidv5]('edf1edf1-3df1-3df1-3df1-3df1edf1edf1', CAST(N'Ed-FiEducationOrganizationInterventionPrescriptionAssociation' AS nvarchar(max)) + N'$$.educationOrganizationReference.educationOrganizationId=' + CAST(i.[EducationOrganization_EducationOrganizationId] AS nvarchar(max)) + N'#' + N'$$.interventionPrescriptionReference.educationOrganizationId=' + CAST(i.[InterventionPrescriptionInterventionPrescription_EducationOrganizationId] AS nvarchar(max)) + N'#' + N'$$.interventionPrescriptionReference.interventionPrescriptionIdentificationCode=' + i.[InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode]), i.[DocumentId], 99
        FROM inserted i INNER JOIN @changedDocs cd ON cd.[DocumentId] = i.[DocumentId];
    END
END;
GO

CREATE OR ALTER TRIGGER [edfi].[TR_EducationOrganizationInterventionPrescriptionAssociation_Stamp]
ON [edfi].[EducationOrganizationInterventionPrescriptionAssociation]
AFTER INSERT, UPDATE, DELETE
AS
BEGIN
    SET NOCOUNT ON;
    ;WITH affectedDocs AS (SELECT [DocumentId] FROM inserted UNION SELECT [DocumentId] FROM deleted)
    UPDATE d
    SET d.[ContentVersion] = NEXT VALUE FOR [dms].[ChangeVersionSequence], d.[ContentLastModifiedAt] = sysutcdatetime()
    FROM [dms].[Document] d
    INNER JOIN affectedDocs a ON d.[DocumentId] = a.[DocumentId];
    IF EXISTS (SELECT 1 FROM deleted) AND (UPDATE([EducationOrganization_EducationOrganizationId]) OR UPDATE([InterventionPrescriptionInterventionPrescription_EducationOrganizationId]) OR UPDATE([InterventionPrescriptionInterventionPrescription_InterventionPrescriptionIdentificationCode]))
    BEGIN
        UPDATE d
        SET d.[IdentityVersion] = NEXT VALUE FOR [dms].[ChangeVersionSequence], d.[IdentityLastModifiedAt] = sysutcdatetime()
        FROM [dms].[Document] d
