CREATE OR ALTER TRIGGER [edfi].[TR_OrganizationDepartment_AbstractIdentity]
ON [edfi].[OrganizationDepartment]
AFTER INSERT, UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM deleted)
    BEGIN
        MERGE [edfi].[EducationOrganizationIdentity] AS t
        USING inserted AS s ON t.[DocumentId] = s.[DocumentId]
        WHEN MATCHED THEN UPDATE SET t.[EducationOrganizationId] = s.[OrganizationDepartmentId]
        WHEN NOT MATCHED THEN INSERT ([DocumentId], [EducationOrganizationId], [Discriminator])
        VALUES (s.[DocumentId], s.[OrganizationDepartmentId], N'Ed-Fi:OrganizationDepartment');
    END
    ELSE IF (UPDATE([OrganizationDepartmentId]))
    BEGIN
        DECLARE @changedDocs TABLE ([DocumentId] bigint NOT NULL);
        INSERT INTO @changedDocs ([DocumentId])
        SELECT i.[DocumentId]
        FROM inserted i INNER JOIN deleted d ON d.[DocumentId] = i.[DocumentId]
        WHERE (i.[OrganizationDepartmentId] <> d.[OrganizationDepartmentId] OR (i.[OrganizationDepartmentId] IS NULL AND d.[OrganizationDepartmentId] IS NOT NULL) OR (i.[OrganizationDepartmentId] IS NOT NULL AND d.[OrganizationDepartmentId] IS NULL));
        MERGE [edfi].[EducationOrganizationIdentity] AS t
        USING (SELECT i.* FROM inserted i INNER JOIN @changedDocs cd ON cd.[DocumentId] = i.[DocumentId]) AS s ON t.[DocumentId] = s.[DocumentId]
        WHEN MATCHED THEN UPDATE SET t.[EducationOrganizationId] = s.[OrganizationDepartmentId]
        WHEN NOT MATCHED THEN INSERT ([DocumentId], [EducationOrganizationId], [Discriminator])
        VALUES (s.[DocumentId], s.[OrganizationDepartmentId], N'Ed-Fi:OrganizationDepartment');
    END
END;
GO

