CREATE OR ALTER TRIGGER [edfi].[TR_PostSecondaryInstitution_AbstractIdentity]
ON [edfi].[PostSecondaryInstitution]
AFTER INSERT, UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM deleted)
    BEGIN
        MERGE [edfi].[EducationOrganizationIdentity] AS t
        USING inserted AS s ON t.[DocumentId] = s.[DocumentId]
        WHEN MATCHED THEN UPDATE SET t.[EducationOrganizationId] = s.[PostSecondaryInstitutionId]
        WHEN NOT MATCHED THEN INSERT ([DocumentId], [EducationOrganizationId], [Discriminator])
        VALUES (s.[DocumentId], s.[PostSecondaryInstitutionId], N'Ed-Fi:PostSecondaryInstitution');
    END
    ELSE IF (UPDATE([PostSecondaryInstitutionId]))
    BEGIN
        DECLARE @changedDocs TABLE ([DocumentId] bigint NOT NULL);
        INSERT INTO @changedDocs ([DocumentId])
        SELECT i.[DocumentId]
        FROM inserted i INNER JOIN deleted d ON d.[DocumentId] = i.[DocumentId]
        WHERE (i.[PostSecondaryInstitutionId] <> d.[PostSecondaryInstitutionId] OR (i.[PostSecondaryInstitutionId] IS NULL AND d.[PostSecondaryInstitutionId] IS NOT NULL) OR (i.[PostSecondaryInstitutionId] IS NOT NULL AND d.[PostSecondaryInstitutionId] IS NULL));
        MERGE [edfi].[EducationOrganizationIdentity] AS t
        USING (SELECT i.* FROM inserted i INNER JOIN @changedDocs cd ON cd.[DocumentId] = i.[DocumentId]) AS s ON t.[DocumentId] = s.[DocumentId]
        WHEN MATCHED THEN UPDATE SET t.[EducationOrganizationId] = s.[PostSecondaryInstitutionId]
        WHEN NOT MATCHED THEN INSERT ([DocumentId], [EducationOrganizationId], [Discriminator])
        VALUES (s.[DocumentId], s.[PostSecondaryInstitutionId], N'Ed-Fi:PostSecondaryInstitution');
    END
END;
GO

