        UPDATE r
        SET r.[Section_LocalCourseCode] = i.[CourseOffering_LocalCourseCode], r.[Section_SchoolId] = i.[CourseOffering_SchoolReferenceSchoolId], r.[Section_SchoolYear] = i.[CourseOffering_SchoolYear], r.[Section_SessionName] = i.[CourseOffering_SessionName], r.[Section_SectionIdentifier] = i.[SectionIdentifier]
        FROM [edfi].[StudentSectionAssociation] r
        INNER JOIN deleted d ON r.[Section_DocumentId] = d.[DocumentId]
        INNER JOIN inserted i ON i.[DocumentId] = d.[DocumentId]
        WHERE (i.[CourseOffering_LocalCourseCode] <> d.[CourseOffering_LocalCourseCode] OR (i.[CourseOffering_LocalCourseCode] IS NULL AND d.[CourseOffering_LocalCourseCode] IS NOT NULL) OR (i.[CourseOffering_LocalCourseCode] IS NOT NULL AND d.[CourseOffering_LocalCourseCode] IS NULL)) OR (i.[CourseOffering_SchoolReferenceSchoolId] <> d.[CourseOffering_SchoolReferenceSchoolId] OR (i.[CourseOffering_SchoolReferenceSchoolId] IS NULL AND d.[CourseOffering_SchoolReferenceSchoolId] IS NOT NULL) OR (i.[CourseOffering_SchoolReferenceSchoolId] IS NOT NULL AND d.[CourseOffering_SchoolReferenceSchoolId] IS NULL)) OR (i.[CourseOffering_SchoolYear] <> d.[CourseOffering_SchoolYear] OR (i.[CourseOffering_SchoolYear] IS NULL AND d.[CourseOffering_SchoolYear] IS NOT NULL) OR (i.[CourseOffering_SchoolYear] IS NOT NULL AND d.[CourseOffering_SchoolYear] IS NULL)) OR (i.[CourseOffering_SessionName] <> d.[CourseOffering_SessionName] OR (i.[CourseOffering_SessionName] IS NULL AND d.[CourseOffering_SessionName] IS NOT NULL) OR (i.[CourseOffering_SessionName] IS NOT NULL AND d.[CourseOffering_SessionName] IS NULL)) OR (i.[SectionIdentifier] <> d.[SectionIdentifier] OR (i.[SectionIdentifier] IS NULL AND d.[SectionIdentifier] IS NOT NULL) OR (i.[SectionIdentifier] IS NOT NULL AND d.[SectionIdentifier] IS NULL));

        UPDATE r
        SET r.[Section_LocalCourseCode] = i.[CourseOffering_LocalCourseCode], r.[Section_SchoolId] = i.[CourseOffering_SchoolReferenceSchoolId], r.[Section_SchoolYear] = i.[CourseOffering_SchoolYear], r.[Section_SessionName] = i.[CourseOffering_SessionName], r.[Section_SectionIdentifier] = i.[SectionIdentifier]
        FROM [edfi].[StudentSectionAttendanceEvent] r
        INNER JOIN deleted d ON r.[Section_DocumentId] = d.[DocumentId]
        INNER JOIN inserted i ON i.[DocumentId] = d.[DocumentId]
        WHERE (i.[CourseOffering_LocalCourseCode] <> d.[CourseOffering_LocalCourseCode] OR (i.[CourseOffering_LocalCourseCode] IS NULL AND d.[CourseOffering_LocalCourseCode] IS NOT NULL) OR (i.[CourseOffering_LocalCourseCode] IS NOT NULL AND d.[CourseOffering_LocalCourseCode] IS NULL)) OR (i.[CourseOffering_SchoolReferenceSchoolId] <> d.[CourseOffering_SchoolReferenceSchoolId] OR (i.[CourseOffering_SchoolReferenceSchoolId] IS NULL AND d.[CourseOffering_SchoolReferenceSchoolId] IS NOT NULL) OR (i.[CourseOffering_SchoolReferenceSchoolId] IS NOT NULL AND d.[CourseOffering_SchoolReferenceSchoolId] IS NULL)) OR (i.[CourseOffering_SchoolYear] <> d.[CourseOffering_SchoolYear] OR (i.[CourseOffering_SchoolYear] IS NULL AND d.[CourseOffering_SchoolYear] IS NOT NULL) OR (i.[CourseOffering_SchoolYear] IS NOT NULL AND d.[CourseOffering_SchoolYear] IS NULL)) OR (i.[CourseOffering_SessionName] <> d.[CourseOffering_SessionName] OR (i.[CourseOffering_SessionName] IS NULL AND d.[CourseOffering_SessionName] IS NOT NULL) OR (i.[CourseOffering_SessionName] IS NOT NULL AND d.[CourseOffering_SessionName] IS NULL)) OR (i.[SectionIdentifier] <> d.[SectionIdentifier] OR (i.[SectionIdentifier] IS NULL AND d.[SectionIdentifier] IS NOT NULL) OR (i.[SectionIdentifier] IS NOT NULL AND d.[SectionIdentifier] IS NULL));

        UPDATE r
        SET r.[Section_LocalCourseCode] = i.[CourseOffering_LocalCourseCode], r.[Section_SchoolId] = i.[CourseOffering_SchoolReferenceSchoolId], r.[Section_SchoolYear] = i.[CourseOffering_SchoolYear], r.[Section_SessionName] = i.[CourseOffering_SessionName], r.[Section_SectionIdentifier] = i.[SectionIdentifier]
        FROM [edfi].[SurveySectionAssociation] r
