CREATE OR ALTER TRIGGER [edfi].[TR_Session_PropagateIdentity]
ON [edfi].[Session]
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    IF (UPDATE([SchoolYear_DocumentId]) OR UPDATE([School_DocumentId]) OR UPDATE([TermDescriptor_DescriptorId]) OR UPDATE([BeginDate]) OR UPDATE([EndDate]) OR UPDATE([SchoolYear_SchoolYear]) OR UPDATE([School_SchoolId]) OR UPDATE([SessionName]) OR UPDATE([TotalInstructionalDays]))
    BEGIN
        UPDATE r
        SET r.[SchoolId_Unified] = i.[School_SchoolId], r.[Session_SchoolYear] = i.[SchoolYear_SchoolYear], r.[Session_SessionName] = i.[SessionName]
        FROM [edfi].[CourseOffering] r
        INNER JOIN deleted d ON r.[Session_DocumentId] = d.[DocumentId]
        INNER JOIN inserted i ON i.[DocumentId] = d.[DocumentId]
        WHERE (i.[School_SchoolId] <> d.[School_SchoolId] OR (i.[School_SchoolId] IS NULL AND d.[School_SchoolId] IS NOT NULL) OR (i.[School_SchoolId] IS NOT NULL AND d.[School_SchoolId] IS NULL)) OR (i.[SchoolYear_SchoolYear] <> d.[SchoolYear_SchoolYear] OR (i.[SchoolYear_SchoolYear] IS NULL AND d.[SchoolYear_SchoolYear] IS NOT NULL) OR (i.[SchoolYear_SchoolYear] IS NOT NULL AND d.[SchoolYear_SchoolYear] IS NULL)) OR (i.[SessionName] <> d.[SessionName] OR (i.[SessionName] IS NULL AND d.[SessionName] IS NOT NULL) OR (i.[SessionName] IS NOT NULL AND d.[SessionName] IS NULL));

        UPDATE r
        SET r.[SchoolId_Unified] = i.[School_SchoolId], r.[Session_SchoolYear] = i.[SchoolYear_SchoolYear], r.[Session_SessionName] = i.[SessionName]
        FROM [edfi].[StudentSchoolAttendanceEvent] r
        INNER JOIN deleted d ON r.[Session_DocumentId] = d.[DocumentId]
        INNER JOIN inserted i ON i.[DocumentId] = d.[DocumentId]
        WHERE (i.[School_SchoolId] <> d.[School_SchoolId] OR (i.[School_SchoolId] IS NULL AND d.[School_SchoolId] IS NOT NULL) OR (i.[School_SchoolId] IS NOT NULL AND d.[School_SchoolId] IS NULL)) OR (i.[SchoolYear_SchoolYear] <> d.[SchoolYear_SchoolYear] OR (i.[SchoolYear_SchoolYear] IS NULL AND d.[SchoolYear_SchoolYear] IS NOT NULL) OR (i.[SchoolYear_SchoolYear] IS NOT NULL AND d.[SchoolYear_SchoolYear] IS NULL)) OR (i.[SessionName] <> d.[SessionName] OR (i.[SessionName] IS NULL AND d.[SessionName] IS NOT NULL) OR (i.[SessionName] IS NOT NULL AND d.[SessionName] IS NULL));

        UPDATE r
        SET r.[Session_SchoolId] = i.[School_SchoolId], r.[SchoolYear_Unified] = i.[SchoolYear_SchoolYear], r.[Session_SessionName] = i.[SessionName]
        FROM [edfi].[Survey] r
        INNER JOIN deleted d ON r.[Session_DocumentId] = d.[DocumentId]
        INNER JOIN inserted i ON i.[DocumentId] = d.[DocumentId]
        WHERE (i.[School_SchoolId] <> d.[School_SchoolId] OR (i.[School_SchoolId] IS NULL AND d.[School_SchoolId] IS NOT NULL) OR (i.[School_SchoolId] IS NOT NULL AND d.[School_SchoolId] IS NULL)) OR (i.[SchoolYear_SchoolYear] <> d.[SchoolYear_SchoolYear] OR (i.[SchoolYear_SchoolYear] IS NULL AND d.[SchoolYear_SchoolYear] IS NOT NULL) OR (i.[SchoolYear_SchoolYear] IS NOT NULL AND d.[SchoolYear_SchoolYear] IS NULL)) OR (i.[SessionName] <> d.[SessionName] OR (i.[SessionName] IS NULL AND d.[SessionName] IS NOT NULL) OR (i.[SessionName] IS NOT NULL AND d.[SessionName] IS NULL));

    END
END;
GO

CREATE OR ALTER TRIGGER [edfi].[TR_Session_ReferentialIdentity]
ON [edfi].[Session]
AFTER INSERT, UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM deleted)
    BEGIN
        DELETE FROM [dms].[ReferentialIdentity]
        WHERE [DocumentId] IN (SELECT [DocumentId] FROM inserted) AND [ResourceKeyId] = 259;
        INSERT INTO [dms].[ReferentialIdentity] ([ReferentialId], [DocumentId], [ResourceKeyId])
        SELECT [dms].[uuidv5]('edf1edf1-3df1-3df1-3df1-3df1edf1edf1', CAST(N'Ed-FiSession' AS nvarchar(max)) + N'$$.schoolReference.schoolId=' + CAST(i.[School_SchoolId] AS nvarchar(max)) + N'#' + N'$$.schoolYearTypeReference.schoolYear=' + CAST(i.[SchoolYear_SchoolYear] AS nvarchar(max)) + N'#' + N'$$.sessionName=' + i.[SessionName]), i.[DocumentId], 259
        FROM inserted i;
    END
    ELSE IF (UPDATE([School_SchoolId]) OR UPDATE([SchoolYear_SchoolYear]) OR UPDATE([SessionName]))
    BEGIN
        DECLARE @changedDocs TABLE ([DocumentId] bigint NOT NULL);
        INSERT INTO @changedDocs ([DocumentId])
        SELECT i.[DocumentId]
        FROM inserted i INNER JOIN deleted d ON d.[DocumentId] = i.[DocumentId]
        WHERE (i.[School_SchoolId] <> d.[School_SchoolId] OR (i.[School_SchoolId] IS NULL AND d.[School_SchoolId] IS NOT NULL) OR (i.[School_SchoolId] IS NOT NULL AND d.[School_SchoolId] IS NULL)) OR (i.[SchoolYear_SchoolYear] <> d.[SchoolYear_SchoolYear] OR (i.[SchoolYear_SchoolYear] IS NULL AND d.[SchoolYear_SchoolYear] IS NOT NULL) OR (i.[SchoolYear_SchoolYear] IS NOT NULL AND d.[SchoolYear_SchoolYear] IS NULL)) OR (i.[SessionName] <> d.[SessionName] OR (i.[SessionName] IS NULL AND d.[SessionName] IS NOT NULL) OR (i.[SessionName] IS NOT NULL AND d.[SessionName] IS NULL));
        DELETE FROM [dms].[ReferentialIdentity]
        WHERE [DocumentId] IN (SELECT [DocumentId] FROM @changedDocs) AND [ResourceKeyId] = 259;
        INSERT INTO [dms].[ReferentialIdentity] ([ReferentialId], [DocumentId], [ResourceKeyId])
        SELECT [dms].[uuidv5]('edf1edf1-3df1-3df1-3df1-3df1edf1edf1', CAST(N'Ed-FiSession' AS nvarchar(max)) + N'$$.schoolReference.schoolId=' + CAST(i.[School_SchoolId] AS nvarchar(max)) + N'#' + N'$$.schoolYearTypeReference.schoolYear=' + CAST(i.[SchoolYear_SchoolYear] AS nvarchar(max)) + N'#' + N'$$.sessionName=' + i.[SessionName]), i.[DocumentId], 259
        FROM inserted i INNER JOIN @changedDocs cd ON cd.[DocumentId] = i.[DocumentId];
    END
END;
