        WHEN NOT MATCHED THEN INSERT ([DocumentId], [BeginDate], [EducationOrganizationReferenceEducationOrganizationId], [ProgramReferenceEducationOrganizationId], [ProgramReferenceProgramName], [ProgramReferenceProgramTypeDescriptor], [StudentReferenceStudentUniqueId], [Discriminator])
        VALUES (s.[DocumentId], s.[BeginDate], s.[EducationOrganization_EducationOrganizationId], s.[ProgramProgram_EducationOrganizationId], s.[ProgramProgram_ProgramName], s.[ProgramProgram_ProgramTypeDescriptor_DescriptorId], s.[Student_StudentUniqueId], N'Ed-Fi:StudentSchoolFoodServiceProgramAssociation');
