CREATE OR ALTER TRIGGER [edfi].[TR_StudentSpecialEducationProgramAssociation_AbstractIdentity]
ON [edfi].[StudentSpecialEducationProgramAssociation]
AFTER INSERT, UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    IF NOT EXISTS (SELECT 1 FROM deleted)
    BEGIN
        MERGE [edfi].[GeneralStudentProgramAssociationIdentity] AS t
        USING inserted AS s ON t.[DocumentId] = s.[DocumentId]
        WHEN MATCHED THEN UPDATE SET t.[BeginDate] = s.[BeginDate], t.[EducationOrganizationReferenceEducationOrganizationId] = s.[EducationOrganization_EducationOrganizationId], t.[ProgramReferenceEducationOrganizationId] = s.[ProgramProgram_EducationOrganizationId], t.[ProgramReferenceProgramName] = s.[ProgramProgram_ProgramName], t.[ProgramReferenceProgramTypeDescriptor] = s.[ProgramProgram_ProgramTypeDescriptor_DescriptorId], t.[StudentReferenceStudentUniqueId] = s.[Student_StudentUniqueId]
        WHEN NOT MATCHED THEN INSERT ([DocumentId], [BeginDate], [EducationOrganizationReferenceEducationOrganizationId], [ProgramReferenceEducationOrganizationId], [ProgramReferenceProgramName], [ProgramReferenceProgramTypeDescriptor], [StudentReferenceStudentUniqueId], [Discriminator])
        VALUES (s.[DocumentId], s.[BeginDate], s.[EducationOrganization_EducationOrganizationId], s.[ProgramProgram_EducationOrganizationId], s.[ProgramProgram_ProgramName], s.[ProgramProgram_ProgramTypeDescriptor_DescriptorId], s.[Student_StudentUniqueId], N'Ed-Fi:StudentSpecialEducationProgramAssociation');
    END
    ELSE IF (UPDATE([BeginDate]) OR UPDATE([EducationOrganization_EducationOrganizationId]) OR UPDATE([ProgramProgram_EducationOrganizationId]) OR UPDATE([ProgramProgram_ProgramName]) OR UPDATE([ProgramProgram_ProgramTypeDescriptor_DescriptorId]) OR UPDATE([Student_StudentUniqueId]))
    BEGIN
        DECLARE @changedDocs TABLE ([DocumentId] bigint NOT NULL);
        INSERT INTO @changedDocs ([DocumentId])
        SELECT i.[DocumentId]
        FROM inserted i INNER JOIN deleted d ON d.[DocumentId] = i.[DocumentId]
        WHERE (i.[BeginDate] <> d.[BeginDate] OR (i.[BeginDate] IS NULL AND d.[BeginDate] IS NOT NULL) OR (i.[BeginDate] IS NOT NULL AND d.[BeginDate] IS NULL)) OR (i.[EducationOrganization_EducationOrganizationId] <> d.[EducationOrganization_EducationOrganizationId] OR (i.[EducationOrganization_EducationOrganizationId] IS NULL AND d.[EducationOrganization_EducationOrganizationId] IS NOT NULL) OR (i.[EducationOrganization_EducationOrganizationId] IS NOT NULL AND d.[EducationOrganization_EducationOrganizationId] IS NULL)) OR (i.[ProgramProgram_EducationOrganizationId] <> d.[ProgramProgram_EducationOrganizationId] OR (i.[ProgramProgram_EducationOrganizationId] IS NULL AND d.[ProgramProgram_EducationOrganizationId] IS NOT NULL) OR (i.[ProgramProgram_EducationOrganizationId] IS NOT NULL AND d.[ProgramProgram_EducationOrganizationId] IS NULL)) OR (i.[ProgramProgram_ProgramName] <> d.[ProgramProgram_ProgramName] OR (i.[ProgramProgram_ProgramName] IS NULL AND d.[ProgramProgram_ProgramName] IS NOT NULL) OR (i.[ProgramProgram_ProgramName] IS NOT NULL AND d.[ProgramProgram_ProgramName] IS NULL)) OR (i.[ProgramProgram_ProgramTypeDescriptor_DescriptorId] <> d.[ProgramProgram_ProgramTypeDescriptor_DescriptorId] OR (i.[ProgramProgram_ProgramTypeDescriptor_DescriptorId] IS NULL AND d.[ProgramProgram_ProgramTypeDescriptor_DescriptorId] IS NOT NULL) OR (i.[ProgramProgram_ProgramTypeDescriptor_DescriptorId] IS NOT NULL AND d.[ProgramProgram_ProgramTypeDescriptor_DescriptorId] IS NULL)) OR (i.[Student_StudentUniqueId] <> d.[Student_StudentUniqueId] OR (i.[Student_StudentUniqueId] IS NULL AND d.[Student_StudentUniqueId] IS NOT NULL) OR (i.[Student_StudentUniqueId] IS NOT NULL AND d.[Student_StudentUniqueId] IS NULL));
        MERGE [edfi].[GeneralStudentProgramAssociationIdentity] AS t
        USING (SELECT i.* FROM inserted i INNER JOIN @changedDocs cd ON cd.[DocumentId] = i.[DocumentId]) AS s ON t.[DocumentId] = s.[DocumentId]
        WHEN MATCHED THEN UPDATE SET t.[BeginDate] = s.[BeginDate], t.[EducationOrganizationReferenceEducationOrganizationId] = s.[EducationOrganization_EducationOrganizationId], t.[ProgramReferenceEducationOrganizationId] = s.[ProgramProgram_EducationOrganizationId], t.[ProgramReferenceProgramName] = s.[ProgramProgram_ProgramName], t.[ProgramReferenceProgramTypeDescriptor] = s.[ProgramProgram_ProgramTypeDescriptor_DescriptorId], t.[StudentReferenceStudentUniqueId] = s.[Student_StudentUniqueId]
        WHEN NOT MATCHED THEN INSERT ([DocumentId], [BeginDate], [EducationOrganizationReferenceEducationOrganizationId], [ProgramReferenceEducationOrganizationId], [ProgramReferenceProgramName], [ProgramReferenceProgramTypeDescriptor], [StudentReferenceStudentUniqueId], [Discriminator])
        VALUES (s.[DocumentId], s.[BeginDate], s.[EducationOrganization_EducationOrganizationId], s.[ProgramProgram_EducationOrganizationId], s.[ProgramProgram_ProgramName], s.[ProgramProgram_ProgramTypeDescriptor_DescriptorId], s.[Student_StudentUniqueId], N'Ed-Fi:StudentSpecialEducationProgramAssociation');
    END
END;
